// -----------------------------------------------------------
//  lfIcon(name, opts) -> SVG-string
// -----------------------------------------------------------
//  Returns an HTML-string (not a DOM node) so it composes
//  cleanly inside template-literals / innerHTML the same way
//  the existing emoji-strings did.
//
//  opts:
//    size  - number (px). Override the SVG width/height attrs
//            (default 24). If you want the SVG to scale via CSS,
//            target `.lf-icon` with `width: 1em; height: 1em`.
//    cls   - string. Extra class name(s) appended after the
//            default 'lf-icon' (caller-controlled).
//    color - string. Sets inline `color:` on the SVG so the
//            currentColor strokes pick it up. Avoid in normal
//            theme-aware code; prefer parent CSS color.
//    title - string. Sets <title> child for a11y. Escaped.
//
//  Fallback: unknown name -> the 'circle-question-mark' icon.
// -----------------------------------------------------------

const _ESC_ATTR_MAP = { '&': '&amp;', '<': '&lt;', '>': '&gt;', '"': '&quot;', "'": '&#39;' };
function _escAttr(s) {
  return String(s == null ? '' : s).replace(/[&<>"']/g, ch => _ESC_ATTR_MAP[ch]);
}

export function lfIcon(name, opts = {}) {
  let raw = ICONS[name];
  let actualName = name;
  if (!raw) {
    // Fallback: render the question-mark icon if available.
    raw = ICONS['circle-question-mark'] || '';
    actualName = 'circle-question-mark';
    if (typeof console !== 'undefined' && console.warn) {
      console.warn('[lfIcon] unknown icon name:', name, '- falling back to circle-question-mark');
    }
  }
  if (!raw) return '';

  // Build the new <svg ...> opening tag attributes.
  // Lucide SVGs already have width="24" height="24" - we can just rewrite them.
  let svg = raw;

  if (opts.size) {
    const sz = Number(opts.size) | 0;
    svg = svg.replace(/width="\d+"/, `width="${sz}"`)
             .replace(/height="\d+"/, `height="${sz}"`);
  }

  // Inject class. Default class is 'lf-icon'; opts.cls is appended.
  const cls = ['lf-icon', `lf-icon--${actualName}`];
  if (opts.cls) cls.push(String(opts.cls));
  const clsStr = _escAttr(cls.join(' '));

  // Inject class + optional inline color via a single replace on the <svg
  // opening tag. Lucide always starts with `<svg xmlns="...`.
  const inlineStyle = opts.color ? ` style="color:${_escAttr(opts.color)}"` : '';
  svg = svg.replace(
    /^<svg /,
    `<svg class="${clsStr}" aria-hidden="true"${inlineStyle} `
  );

  // Optional <title> for a11y (becomes screen-reader-readable).
  if (opts.title) {
    const t = `<title>${_escAttr(opts.title)}</title>`;
    // Insert as the first child of <svg>.
    svg = svg.replace(/(<svg[^>]*>)/, `$1${t}`);
  }

  return svg;
}

// -----------------------------------------------------------
//  lfFlag(code, opts) -> SVG-string  (Mission 8 Q2 override)
// -----------------------------------------------------------
//  Country-flag renderer. Mirrors lfIcon() API but pulls from
//  the FLAGS map (lipis/flag-icons, MIT). Country flags use
//  hardcoded national colors (red/white/blue for GB) — they
//  are NOT theme-tinted via currentColor. That is by design;
//  a flag with the wrong colors is no longer that flag.
//
//  opts: same shape as lfIcon's opts. `color` is ignored
//        because the SVG carries explicit fills.
//
//  Fallback: unknown code -> empty string + console.warn.
// -----------------------------------------------------------

export function lfFlag(code, opts = {}) {
  const key = String(code || '').toLowerCase();
  const raw = FLAGS[key];
  if (!raw) {
    if (typeof console !== 'undefined' && console.warn) {
      console.warn('[lfFlag] unknown flag code:', code);
    }
    return '';
  }
  let svg = raw;

  // Default sizing: width 1.4em / height 1em keeps the 4:3 ratio inline
  // alongside text. opts.size overrides both with a square pixel size.
  if (opts.size) {
    const sz = Number(opts.size) | 0;
    // Set or override width/height attrs.
    if (/width="[^"]*"/.test(svg)) svg = svg.replace(/width="[^"]*"/, `width="${sz}"`);
    if (/height="[^"]*"/.test(svg)) svg = svg.replace(/height="[^"]*"/, `height="${sz}"`);
  }

  const cls = ['lf-flag', `lf-flag--${key}`];
  if (opts.cls) cls.push(String(opts.cls));
  const clsStr = _escAttr(cls.join(' '));

  svg = svg.replace(
    /^<svg /,
    `<svg class="${clsStr}" aria-hidden="true" `
  );

  if (opts.title) {
    const t = `<title>${_escAttr(opts.title)}</title>`;
    svg = svg.replace(/(<svg[^>]*>)/, `$1${t}`);
  }

  return svg;
}

// Convenience: register on window.LF for inline-onclick / non-module access.
if (typeof window !== 'undefined') {
  window.LF = window.LF || {};
  window.LF.lfIcon = lfIcon;
  window.LF.lfFlag = lfFlag;
  window.LF.ICONS = ICONS;
  window.LF.FLAGS = FLAGS;
}
